#include <iostream>
#include <queue>
#include <vector>
#include <algorithm>

using namespace std;

const int MAXN = 100;

vector<int> adj[MAXN]; // adjacency list representation of the graph
int n;                  // number of vertices

void dijkstra() {
    priority_queue<int, vector<int>, Compare> queue;
    queue.push(0); // source vertex
    vector<bool> visited(MAXN, false);

    while (!queue.empty()) {
        int u = queue.top();
        queue.pop();

        if (visited[u]) {
            continue; // vertex has been visited
        }

        visited[u] = true;

        for (int v : adj[u]) {
            if (!visited[v]) {
                queue.push(v); // push unvisited neighbor
            }
        }
    }
}

int Compare(int a, int b) {
    return abs(a - b); // use absolute value to break ties
}

int main() {
    n = MAXN;

    // add edges to the graph
    adj[0].push_back(1);
    adj[0].push_back(4);
    adj[1].push_back(0);
    adj[1].push_back(2);
    adj[1].push_back(3);
    adj[2].push_back(1);
    adj[2].push_back(3);
    adj[3].push_back(1);
    adj[3].push_back(4);
    adj[3].push_back(2);
    adj[4].push_back(0);
    adj[4].push_back(3);
    adj[4].push_back(2);
    adj[5].push_back(0);
    adj[5].push_back(1);
    adj[5].push_back(4);
    adj[5].push_back(3);

    // run Dijkstra's algorithm
    dijkstra();

    // print the shortest path from source to all other vertices
    for (int i = 1; i < n; i++) {
        cout << i << " : ";
        int u = find(visited, visited + n, i);
        cout << "-" << endl;
        while (u != -1) {
            cout << adj[u] << " ";
            u = find(visited, visited + n, adj[u]);
        }
        cout << endl;
    }

    return 0;
}
```
